import{_ as t,o,c as a,ag as d}from"./chunks/framework.BDReElpY.js";const g=JSON.parse('{"title":"Lexical Structure","description":"","frontmatter":{},"headers":[],"relativePath":"archive/reference/lexical.md","filePath":"archive/reference/lexical.md"}'),c={name:"archive/reference/lexical.md"};function l(i,e,n,r,s,p){return o(),a("div",null,[...e[0]||(e[0]=[d(`<h1 id="lexical-structure" tabindex="-1">Lexical Structure <a class="header-anchor" href="#lexical-structure" aria-label="Permalink to &quot;Lexical Structure&quot;">​</a></h1><p><strong>Core Language Specification</strong><br><strong>Version:</strong> 0.2.0<br><strong>Status:</strong> ✅ Implemented</p><p>This document defines the lexical structure of Vex, including allowed characters, tokenization rules, and automatic semicolon insertion.</p><hr><h2 id="_1-source-code-encoding" tabindex="-1">1. Source Code Encoding <a class="header-anchor" href="#_1-source-code-encoding" aria-label="Permalink to &quot;1. Source Code Encoding&quot;">​</a></h2><ul><li><strong>File Extension</strong>: <code>.vx</code></li><li><strong>Encoding</strong>: UTF-8</li><li><strong>Newline</strong>: LF (<code>\\n</code>) or CRLF (<code>\\r\\n</code>)</li></ul><h2 id="_2-comments" tabindex="-1">2. Comments <a class="header-anchor" href="#_2-comments" aria-label="Permalink to &quot;2. Comments&quot;">​</a></h2><p>Comments are ignored by the parser but may be used by documentation tools.</p><table tabindex="0"><thead><tr><th style="text-align:left;">Type</th><th style="text-align:left;">Syntax</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>Line Comment</strong></td><td style="text-align:left;"><code>// text</code></td><td style="text-align:left;">Ends at newline.</td></tr><tr><td style="text-align:left;"><strong>Block Comment</strong></td><td style="text-align:left;"><code>/* text */</code></td><td style="text-align:left;">Can span multiple lines. Does not nest.</td></tr><tr><td style="text-align:left;"><strong>Doc Line</strong></td><td style="text-align:left;"><code>/// text</code></td><td style="text-align:left;">Documentation for the following item.</td></tr><tr><td style="text-align:left;"><strong>Doc Block</strong></td><td style="text-align:left;"><code>/** text */</code></td><td style="text-align:left;">Block documentation.</td></tr></tbody></table><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Regular comment</span></span>
<span class="line"><span>/// Documented function</span></span>
<span class="line"><span>fn main() { /* ... */ }</span></span></code></pre></div><h2 id="_3-whitespace-asi" tabindex="-1">3. Whitespace &amp; ASI <a class="header-anchor" href="#_3-whitespace-asi" aria-label="Permalink to &quot;3. Whitespace &amp; ASI&quot;">​</a></h2><p>Vex uses <strong>Automatic Semicolon Insertion (ASI)</strong>. Semicolons <code>;</code> are <strong>optional</strong> at the end of statements.</p><p>The lexer automatically implies a semicolon if a newline occurs after a statement-ending token (like Identifier, Literal, <code>)</code>, <code>}</code>, etc.).</p><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// Valid Vex code</span></span>
<span class="line"><span>let x = 10</span></span>
<span class="line"><span>let y = 20</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// Also valid</span></span>
<span class="line"><span>let a = 1; let b = 2;</span></span></code></pre></div><h2 id="_4-identifiers" tabindex="-1">4. Identifiers <a class="header-anchor" href="#_4-identifiers" aria-label="Permalink to &quot;4. Identifiers&quot;">​</a></h2><p>Names for variables, types, and functions.</p><ul><li><strong>Start</strong>: <code>[a-zA-Z_]</code></li><li><strong>Continue</strong>: <code>[a-zA-Z0-9_]</code></li><li><strong>Case Sensitive</strong></li></ul><div class="language-vex vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">vex</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>my_var</span></span>
<span class="line"><span>MyStruct</span></span>
<span class="line"><span>_internal</span></span></code></pre></div><h2 id="_5-keywords" tabindex="-1">5. Keywords <a class="header-anchor" href="#_5-keywords" aria-label="Permalink to &quot;5. Keywords&quot;">​</a></h2><p>Reserved words that cannot be used as identifiers.</p><h3 id="declaration" tabindex="-1">Declaration <a class="header-anchor" href="#declaration" aria-label="Permalink to &quot;Declaration&quot;">​</a></h3><p><code>fn</code>, <code>let</code>, <code>let!</code>, <code>const</code>, <code>struct</code>, <code>enum</code>, <code>contract</code>, <code>impl</code>, <code>policy</code>, <code>type</code>, <code>unsafe</code>, <code>extern</code></p><h3 id="control-flow" tabindex="-1">Control Flow <a class="header-anchor" href="#control-flow" aria-label="Permalink to &quot;Control Flow&quot;">​</a></h3><p><code>if</code>, <code>else</code>, <code>elif</code>, <code>for</code>, <code>while</code>, <code>loop</code>, <code>match</code>, <code>switch</code>, <code>case</code>, <code>default</code>, <code>return</code>, <code>break</code>, <code>continue</code>, <code>defer</code>, <code>try</code></p><h3 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h3><p><code>i8</code>..<code>i128</code>, <code>u8</code>..<code>u128</code>, <code>f16</code>..<code>f64</code>, <code>bool</code>, <code>string</code>, <code>byte</code>, <code>any</code>, <code>never</code>, <code>error</code>, <code>nil</code>, <code>typeof</code></p><h3 id="concurrency" tabindex="-1">Concurrency <a class="header-anchor" href="#concurrency" aria-label="Permalink to &quot;Concurrency&quot;">​</a></h3><p><code>async</code>, <code>await</code>, <code>go</code>, <code>select</code></p><h3 id="modules" tabindex="-1">Modules <a class="header-anchor" href="#modules" aria-label="Permalink to &quot;Modules&quot;">​</a></h3><p><code>import</code>, <code>export</code>, <code>from</code>, <code>as</code></p><h3 id="constraints-metaprogramming" tabindex="-1">Constraints &amp; Metaprogramming <a class="header-anchor" href="#constraints-metaprogramming" aria-label="Permalink to &quot;Constraints &amp; Metaprogramming&quot;">​</a></h3><p><code>extends</code>, <code>infer</code>, <code>where</code>, <code>asm</code></p><h3 id="deprecated-legacy" tabindex="-1">Deprecated / Legacy <a class="header-anchor" href="#deprecated-legacy" aria-label="Permalink to &quot;Deprecated / Legacy&quot;">​</a></h3><p><code>interface</code> (Removed), <code>launch</code> (Deprecated), <code>gpu</code> (Deprecated)</p><h2 id="_6-operators" tabindex="-1">6. Operators <a class="header-anchor" href="#_6-operators" aria-label="Permalink to &quot;6. Operators&quot;">​</a></h2><h3 id="arithmetic-bitwise" tabindex="-1">Arithmetic &amp; Bitwise <a class="header-anchor" href="#arithmetic-bitwise" aria-label="Permalink to &quot;Arithmetic &amp; Bitwise&quot;">​</a></h3><p><code>+</code>, <code>-</code>, <code>*</code>, <code>/</code>, <code>%</code><code>&amp;</code>, <code>|</code>, <code>^</code>, <code>~</code>, <code>&lt;&lt;</code>, <code>&gt;&gt;</code></p><h3 id="comparison-logic" tabindex="-1">Comparison &amp; Logic <a class="header-anchor" href="#comparison-logic" aria-label="Permalink to &quot;Comparison &amp; Logic&quot;">​</a></h3><p><code>==</code>, <code>!=</code>, <code>&lt;</code>, <code>&lt;=</code>, <code>&gt;</code>, <code>&gt;=</code><code>&amp;&amp;</code>, <code>||</code>, <code>!</code></p><h3 id="assignment" tabindex="-1">Assignment <a class="header-anchor" href="#assignment" aria-label="Permalink to &quot;Assignment&quot;">​</a></h3><p><code>=</code>, <code>+=</code>, <code>-=</code>, <code>*=</code>, <code>/=</code>, <code>%=</code>, <code>&amp;=</code>, <code>|=</code>, <code>^=</code>, <code>&lt;&lt;=</code>, <code>&gt;&gt;=</code></p><h3 id="advanced-simd-implemented" tabindex="-1">Advanced / SIMD (Implemented) <a class="header-anchor" href="#advanced-simd-implemented" aria-label="Permalink to &quot;Advanced / SIMD (Implemented)&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;&lt;&lt;</code></td><td style="text-align:left;">Rotate Left</td><td style="text-align:left;">Bitwise rotation</td></tr><tr><td style="text-align:left;"><code>&gt;&gt;&gt;</code></td><td style="text-align:left;">Rotate Right</td><td style="text-align:left;">Bitwise rotation</td></tr><tr><td style="text-align:left;"><code>+|</code>, <code>-|</code>, <code>*|</code></td><td style="text-align:left;">Saturating</td><td style="text-align:left;">Saturating arithmetic</td></tr><tr><td style="text-align:left;"><code>*^</code></td><td style="text-align:left;">Carry-less Mul</td><td style="text-align:left;">Crypto acceleration</td></tr><tr><td style="text-align:left;"><code>&lt;?</code>, <code>&gt;?</code></td><td style="text-align:left;">Min/Max</td><td style="text-align:left;">SIMD min/max</td></tr></tbody></table><h3 id="pipeline-functional" tabindex="-1">Pipeline &amp; Functional <a class="header-anchor" href="#pipeline-functional" aria-label="Permalink to &quot;Pipeline &amp; Functional&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Operator</th><th style="text-align:left;">Name</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>|&gt;</code></td><td style="text-align:left;">Pipeline</td><td style="text-align:left;">Function chaining</td></tr><tr><td style="text-align:left;"><code>-&gt;&gt;</code></td><td style="text-align:left;">Arrow</td><td style="text-align:left;">(Reserved)</td></tr></tbody></table><h3 id="matrix-linear-algebra" tabindex="-1">Matrix / Linear Algebra <a class="header-anchor" href="#matrix-linear-algebra" aria-label="Permalink to &quot;Matrix / Linear Algebra&quot;">​</a></h3><p><code>&lt;*&gt;</code>, <code>&lt;^&gt;</code>, <code>&lt;\\&gt;</code></p><h3 id="special" tabindex="-1">Special <a class="header-anchor" href="#special" aria-label="Permalink to &quot;Special&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Symbol</th><th style="text-align:left;">Usage</th></tr></thead><tbody><tr><td style="text-align:left;"><code>.</code></td><td style="text-align:left;">Member access</td></tr><tr><td style="text-align:left;"><code>..</code></td><td style="text-align:left;">Exclusive Range</td></tr><tr><td style="text-align:left;"><code>..=</code></td><td style="text-align:left;">Inclusive Range</td></tr><tr><td style="text-align:left;"><code>...</code></td><td style="text-align:left;">Rest / Spread</td></tr><tr><td style="text-align:left;"><code>?.</code></td><td style="text-align:left;">Optional Chaining</td></tr><tr><td style="text-align:left;"><code>??</code></td><td style="text-align:left;">Null Coalesce</td></tr><tr><td style="text-align:left;"><code>!&gt;</code></td><td style="text-align:left;">Error Rescue</td></tr><tr><td style="text-align:left;"><code>-&gt;</code></td><td style="text-align:left;">Return Type Arrow</td></tr><tr><td style="text-align:left;"><code>=&gt;</code></td><td style="text-align:left;">Fat Arrow</td></tr><tr><td style="text-align:left;"><code>&lt;-</code></td><td style="text-align:left;">Channel Receive</td></tr><tr><td style="text-align:left;"><code>@</code></td><td style="text-align:left;">Autograd Marker</td></tr></tbody></table><h2 id="_7-metaprogramming-comptime" tabindex="-1">7. Metaprogramming &amp; Comptime <a class="header-anchor" href="#_7-metaprogramming-comptime" aria-label="Permalink to &quot;7. Metaprogramming &amp; Comptime&quot;">​</a></h2><p>Vex supports compile-time logic with <code>$</code> prefix.</p><ul><li><code>$for</code>, <code>$while</code></li><li><code>$if</code>, <code>$elif</code>, <code>$else</code></li><li><code>$typeof</code>, <code>$const</code></li><li><code>$concat</code>, <code>$stringify</code></li></ul><h2 id="_8-literals" tabindex="-1">8. Literals <a class="header-anchor" href="#_8-literals" aria-label="Permalink to &quot;8. Literals&quot;">​</a></h2><p>Vex supports specific suffixes and formats.</p><ul><li><strong>Integers</strong>: <code>100</code>, <code>0xFF</code>, <code>0o77</code>, <code>0b1010</code>. Suffixes: <code>42u8</code>, <code>100i64</code></li><li><strong>Floats</strong>: <code>3.14</code>, <code>1.5e-10</code>.</li><li><strong>Strings</strong>: <code>&quot;text&quot;</code>, <code>f&quot;hello {name}&quot;</code></li><li><strong>Chars</strong>: Not a distinct type (use string or byte).</li></ul><h2 id="_9-compiler-directives" tabindex="-1">9. Compiler Directives <a class="header-anchor" href="#_9-compiler-directives" aria-label="Permalink to &quot;9. Compiler Directives&quot;">​</a></h2><p>Intrinsics start with <code>@</code>.</p><ul><li><code>@{ ... }</code> (Intrinsic Block)</li><li><code>@vectorize</code> (Deprecated, auto)</li><li><code>@gpu</code> (Deprecated, auto)</li></ul>`,58)])])}const m=t(c,[["render",l]]);export{g as __pageData,m as default};
